import { describe, expect, it } from "vitest";
import { mergeIntervals } from "../src/merge.js";

// Behavior under test (from src/merge.js):
//   mergeIntervals(intervals)
//     intervals: Array of [start, end] pairs with start <= end.
//     Returns a NEW array of merged intervals, sorted by start ascending:
//       - overlapping intervals are merged ([1,4],[3,6] -> [1,6])
//       - touching intervals are merged ([1,2],[2,3] -> [1,3])
//       - disjoint intervals stay separate
//       - [] -> []
//       - the input array and its pairs are never mutated
//       - throws RangeError if any pair has start > end

describe("mergeIntervals", () => {
  describe("empty and singleton inputs", () => {
    it("returns [] for an empty input", () => {
      expect(mergeIntervals([])).toEqual([]);
    });

    it("returns a single interval unchanged (by value)", () => {
      expect(mergeIntervals([[1, 5]])).toEqual([[1, 5]]);
    });

    it("preserves a single point interval where start === end", () => {
      expect(mergeIntervals([[3, 3]])).toEqual([[3, 3]]);
    });
  });

  describe("overlapping intervals", () => {
    it("merges two overlapping intervals (documented example)", () => {
      expect(mergeIntervals([[1, 4], [3, 6]])).toEqual([[1, 6]]);
    });

    it("merges when the second interval is fully contained in the first", () => {
      expect(mergeIntervals([[1, 10], [2, 3]])).toEqual([[1, 10]]);
    });

    it("keeps the larger end when a later interval ends earlier", () => {
      // [1,10] then [4,6]: end must remain 10, not shrink to 6.
      expect(mergeIntervals([[1, 10], [4, 6]])).toEqual([[1, 10]]);
    });

    it("merges a chain of overlapping intervals into one", () => {
      expect(mergeIntervals([[1, 3], [2, 5], [4, 8]])).toEqual([[1, 8]]);
    });

    it("merges duplicate intervals into a single interval", () => {
      expect(mergeIntervals([[2, 4], [2, 4]])).toEqual([[2, 4]]);
    });

    it("merges intervals that share the same start", () => {
      expect(mergeIntervals([[1, 3], [1, 7]])).toEqual([[1, 7]]);
    });

    it("merges intervals that share the same end", () => {
      expect(mergeIntervals([[1, 8], [5, 8]])).toEqual([[1, 8]]);
    });
  });

  describe("touching intervals", () => {
    it("merges two touching intervals (documented example)", () => {
      expect(mergeIntervals([[1, 2], [2, 3]])).toEqual([[1, 3]]);
    });

    it("merges when one interval touches a point interval", () => {
      expect(mergeIntervals([[1, 5], [5, 5]])).toEqual([[1, 5]]);
    });

    it("merges a run of intervals that each touch the next", () => {
      expect(mergeIntervals([[1, 2], [2, 3], [3, 4]])).toEqual([[1, 4]]);
    });
  });

  describe("disjoint intervals", () => {
    it("keeps two disjoint intervals separate", () => {
      expect(mergeIntervals([[1, 2], [4, 5]])).toEqual([[1, 2], [4, 5]]);
    });

    it("does not merge intervals separated by a unit gap", () => {
      // [1,2] and [3,4] do not touch (2 < 3), so they stay separate.
      expect(mergeIntervals([[1, 2], [3, 4]])).toEqual([[1, 2], [3, 4]]);
    });

    it("keeps disjoint point intervals separate", () => {
      expect(mergeIntervals([[1, 1], [3, 3]])).toEqual([[1, 1], [3, 3]]);
    });
  });

  describe("sorting", () => {
    it("returns intervals sorted by start ascending", () => {
      expect(mergeIntervals([[5, 6], [1, 2], [3, 4]])).toEqual([
        [1, 2],
        [3, 4],
        [5, 6],
      ]);
    });

    it("merges correctly regardless of input order", () => {
      expect(mergeIntervals([[3, 6], [1, 4]])).toEqual([[1, 6]]);
    });

    it("merges an unsorted, interleaved mix of overlaps and gaps", () => {
      expect(
        mergeIntervals([[8, 10], [1, 3], [2, 6], [15, 18], [9, 12]])
      ).toEqual([
        [1, 6],
        [8, 12],
        [15, 18],
      ]);
    });
  });

  describe("negative and mixed-sign values", () => {
    it("handles negative intervals", () => {
      expect(mergeIntervals([[-5, -2], [-3, -1]])).toEqual([[-5, -1]]);
    });

    it("merges an interval spanning zero", () => {
      expect(mergeIntervals([[-2, 2], [1, 4]])).toEqual([[-2, 4]]);
    });

    it("sorts and keeps disjoint negative and positive intervals separate", () => {
      expect(mergeIntervals([[3, 5], [-4, -2]])).toEqual([[-4, -2], [3, 5]]);
    });
  });

  describe("non-integer values", () => {
    it("merges overlapping fractional intervals", () => {
      expect(mergeIntervals([[1.5, 2.5], [2.0, 3.5]])).toEqual([[1.5, 3.5]]);
    });

    it("keeps fractional intervals with a tiny gap separate", () => {
      expect(mergeIntervals([[0, 1], [1.5, 2]])).toEqual([[0, 1], [1.5, 2]]);
    });
  });

  describe("invalid intervals", () => {
    it("throws RangeError when a pair has start > end", () => {
      expect(() => mergeIntervals([[5, 1]])).toThrow(RangeError);
    });

    it("includes the offending interval in the error message", () => {
      expect(() => mergeIntervals([[5, 1]])).toThrow("[5, 1]");
    });

    it("throws when any pair among valid ones is invalid", () => {
      expect(() => mergeIntervals([[1, 2], [9, 3], [4, 5]])).toThrow(
        RangeError
      );
    });

    it("does not throw for a valid point interval where start === end", () => {
      expect(() => mergeIntervals([[4, 4]])).not.toThrow();
    });
  });

  describe("immutability", () => {
    it("does not mutate the input array", () => {
      const input = [[3, 6], [1, 4]];
      mergeIntervals(input);
      expect(input).toEqual([[3, 6], [1, 4]]);
    });

    it("does not mutate the individual input pairs", () => {
      const a = [1, 4];
      const b = [3, 6];
      mergeIntervals([a, b]);
      expect(a).toEqual([1, 4]);
      expect(b).toEqual([3, 6]);
    });

    it("preserves input pair length (does not add or remove elements)", () => {
      const input = [[1, 4], [3, 6]];
      mergeIntervals(input);
      expect(input).toHaveLength(2);
      expect(input[0]).toHaveLength(2);
      expect(input[1]).toHaveLength(2);
    });

    it("returns a fresh array, not the input reference", () => {
      const input = [[1, 5]];
      const result = mergeIntervals(input);
      expect(result).not.toBe(input);
    });

    it("returns fresh pair objects, distinct from the input pairs", () => {
      const pair = [1, 5];
      const result = mergeIntervals([pair]);
      expect(result[0]).not.toBe(pair);
    });

    it("mutating the result does not affect the input", () => {
      const input = [[1, 5]];
      const result = mergeIntervals(input);
      result[0][1] = 999;
      expect(input).toEqual([[1, 5]]);
    });
  });

  describe("larger / combined scenarios", () => {
    it("handles many intervals collapsing to a single interval", () => {
      const input = [];
      for (let i = 0; i < 100; i++) {
        input.push([i, i + 1]);
      }
      // Each touches the next: [0,1],[1,2],...,[99,100] -> [0,100].
      expect(mergeIntervals(input)).toEqual([[0, 100]]);
    });

    it("preserves fully disjoint intervals in sorted order", () => {
      const input = [[10, 11], [0, 1], [4, 5], [7, 8]];
      expect(mergeIntervals(input)).toEqual([
        [0, 1],
        [4, 5],
        [7, 8],
        [10, 11],
      ]);
    });

    it("merges a mixture where some overlap, touch, and stay disjoint", () => {
      expect(
        mergeIntervals([[1, 3], [3, 5], [7, 9], [8, 8], [12, 20], [15, 16]])
      ).toEqual([
        [1, 5],
        [7, 9],
        [12, 20],
      ]);
    });
  });
});

